import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
public class SimpleTest {
    @Test
    public void testX() {
        assertEquals(next("foo"), "bar"); // wrong argument order
        assertEquals("bar", next("foo")); // good
        assertEquals("foo", "bar", "reason"); // not covered by this rule
        assertEquals("foo", "foo", "other reason"); // not covered by this rule
    }

    private String next(String in) {
        return "bar";
    }
}


